import ast
import json
import sys
from typing import Any, List

import redis


def parse_value(value: str) -> Any:
    try:
        return ast.literal_eval(value)
    except Exception:
        return value


def to_redis_arg(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, (dict, list, tuple, set)):
        return json.dumps(list(value) if isinstance(value, set) else value, separators=(",", ":"))
    return str(value)


def read_multiline(prompt: str) -> str:
    print(prompt, file=sys.stderr)
    print("End input with a line containing only EOF", file=sys.stderr)
    lines: List[str] = []
    while True:
        try:
            line = input()
        except EOFError:
            break
        if line == "EOF":
            break
        lines.append(line)
    return "\n".join(lines)


def main() -> None:
    host = input("Redis host [localhost]: ").strip() or "localhost"
    port_raw = input("Redis port [6379]: ").strip() or "6379"
    db_raw = input("Redis db [0]: ").strip() or "0"
    password = input("Redis password [empty]: ")
    decode_responses_raw = input("Decode responses? [y/N]: ").strip().lower()
    decode_responses = decode_responses_raw in {"y", "yes", "true", "1"}

    client = redis.Redis(
        host=host,
        port=int(port_raw),
        db=int(db_raw),
        password=password or None,
        decode_responses=decode_responses,
    )

    script = read_multiline("Enter Lua script:")
    numkeys_raw = input("Number of KEYS passed to Lua script [0]: ").strip() or "0"
    numkeys = int(numkeys_raw)

    keys = []
    for i in range(numkeys):
        keys.append(input(f"KEYS[{i + 1}]: "))

    arg_count_raw = input("Number of ARGV passed to Lua script [0]: ").strip() or "0"
    arg_count = int(arg_count_raw)

    args = []
    for i in range(arg_count):
        raw = input(f"ARGV[{i + 1}]: ")
        parsed = parse_value(raw)
        args.append(to_redis_arg(parsed))

    try:
        result = client.eval(script, numkeys, *(keys + args))
        if isinstance(result, (dict, list, tuple)):
            print(json.dumps(result, ensure_ascii=False))
        else:
            print(result)
    except Exception as e:
        print(f"Redis eval failed: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()